   103â†’void
   104â†’usage( void )
   105â†’{
   106â†’	fprintf( stderr, _("Add or modify entries from an LDAP server\n\n"));
   107â†’	fprintf( stderr, _("usage: %s [options]\n"), prog);
   108â†’	fprintf( stderr, _("	The list of desired operations are read from stdin"
   109â†’		" or from the file\n"));
   110â†’	fprintf( stderr, _("	specified by \"-f file\".\n"));
   111â†’	fprintf( stderr, _("Add or modify options:\n"));
   112â†’	fprintf( stderr, _("  -a         add values (%s)\n"),
   113â†’		(ldapadd ? _("default") : _("default is to replace")));
   114â†’	fprintf( stderr, _("  -c         continuous operation mode (do not stop on errors)\n"));
   115â†’	fprintf( stderr, _("  -E [!]ext=extparam	modify extensions"
   116â†’		" (! indicate s criticality)\n"));
   117â†’	fprintf( stderr, _("  -f file    read operations from `file'\n"));
   118â†’	fprintf( stderr, _("  -i time    wait `time' microseconds between operations\n"));
   119â†’	fprintf( stderr, _("  -M         enable Manage DSA IT control (-MM to make critical)\n"));
   120â†’	fprintf( stderr, _("  -P version protocol version (default: 3)\n"));
   121â†’ 	fprintf( stderr,
   122â†’		_("             [!]txn=<commit|abort>         (transaction)\n"));
   123â†’	fprintf( stderr, _("  -S file    write skipped modifications to `file'\n"));
   124â†’
   125â†’	tool_common_usage();
   126â†’	exit( EXIT_FAILURE );
   127â†’}
