   129â†’
   130â†’const char options[] = "aE:rS:"
   131â†’	"cd:D:e:f:h:H:i:IMnNO:o:p:P:QR:U:vVw:WxX:y:Y:Z";
   132â†’
   133â†’int
   134â†’handle_private_option( int i )
   135â†’{
   136â†’	char	*control, *cvalue;
   137â†’	int		crit;
   138â†’
   139â†’	switch ( i ) {
   140â†’	case 'E': /* modify extensions */
   141â†’		if( protocol == LDAP_VERSION2 ) {
   142â†’			fprintf( stderr, _("%s: -E incompatible with LDAPv%d\n"),
   143â†’				prog, protocol );
   144â†’			exit( EXIT_FAILURE );
   145â†’		}
   146â†’
   147â†’		/* should be extended to support comma separated list of
   148â†’		 *	[!]key[=value] parameters, e.g.  -E !foo,bar=567
   149â†’		 */
   150â†’
   151â†’		crit = 0;
   152â†’		cvalue = NULL;
   153â†’		if( optarg[0] == '!' ) {
   154â†’			crit = 1;
   155â†’			optarg++;
   156â†’		}
   157â†’
   158â†’		control = optarg;
   159â†’		if ( (cvalue = strchr( control, '=' )) != NULL ) {
   160â†’			*cvalue++ = '\0';
   161â†’		}
   162â†’
   163â†’		if( strcasecmp( control, "txn" ) == 0 ) {
   164â†’			/* Transaction */
   165â†’			if( txn ) {
   166â†’				fprintf( stderr,
   167â†’					_("txn control previously specified\n"));
   168â†’				exit( EXIT_FAILURE );
   169â†’			}
   170â†’			if( cvalue != NULL ) {
   171â†’				if( strcasecmp( cvalue, "abort" ) == 0 ) {
   172â†’					txnabort=1;
   173â†’				} else if( strcasecmp( cvalue, "commit" ) != 0 ) {
   174â†’					fprintf( stderr, _("Invalid value for txn control, %s\n"),
   175â†’						cvalue );
   176â†’					exit( EXIT_FAILURE );
   177â†’				}
   178â†’			}
   179â†’
   180â†’			txn = 1 + crit;
   181â†’		} else
   182â†’		{
   183â†’			fprintf( stderr, _("Invalid modify extension name: %s\n"),
   184â†’				control );
   185â†’			usage();
   186â†’		}
   187â†’		break;
   188â†’
   189â†’	case 'a':	/* add */
   190â†’		ldapadd = 1;
   191â†’		break;
   192â†’
   193â†’	case 'i':	/* interval */
   194â†’		{
   195â†’			char *next;
   196â†’			interval = strtol( optarg, &next, 10 );
   197â†’			if ( !next || *next ) {
   198â†’				fprintf( stderr, "%s: unable to parse interval \"%s\"\n", prog, optarg);
   199â†’                exit(EXIT_FAILURE);
   200â†’			}
   201â†’			interval_tv.tv_usec = interval % 1000000;
   202â†’			interval_tv.tv_sec = interval / 1000000;
   203â†’		}
   204â†’		break;
   205â†’
   206â†’	case 'r':	/* replace (obsolete) */
   207â†’		break;
   208â†’
   209â†’	case 'S':	/* skipped modifications to file */
   210â†’		if( rejfile != NULL ) {
   211â†’			fprintf( stderr, _("%s: -S previously specified\n"), prog );
   212â†’			exit( EXIT_FAILURE );
   213â†’		}
   214â†’		rejfile = optarg;
   215â†’		break;
   216â†’
   217â†’	default:
   218â†’		return 0;
   219â†’	}
   220â†’	return 1;
   221â†’}
