   224â†’int
   225â†’main( int argc, char **argv )
   226â†’{
   227â†’	char		*rbuf = NULL, *rejbuf = NULL;
   228â†’	FILE		*rejfp;
   229â†’	struct LDIFFP *ldiffp = NULL, ldifdummy = {0};
   230â†’	char		*matched_msg, *error_msg;
   231â†’	int		rc, retval, ldifrc;
   232â†’	int		len;
   233â†’	int		i = 0, lmax = 0;
   234â†’	unsigned long	lineno, nextline = 0;
   235â†’	LDAPControl	c[1];
   236â†’
   237â†’	prog = lutil_progname( "ldapmodify", argc, argv );
   238â†’
   239â†’	/* strncmp instead of strcmp since NT binaries carry .exe extension */
   240â†’	ldapadd = ( strncasecmp( prog, "ldapadd", sizeof("ldapadd")-1 ) == 0 );
   241â†’
   242â†’	tool_init( ldapadd ? TOOL_ADD : TOOL_MODIFY );
   243â†’
   244â†’	tool_args( argc, argv );
   245â†’
   246â†’	if ( argc != optind ) usage();
   247â†’
   248â†’	if ( rejfile != NULL ) {
   249â†’		if (( rejfp = fopen( rejfile, "w" )) == NULL ) {
   250â†’			perror( rejfile );
   251â†’			retval = EXIT_FAILURE;
   252â†’			goto fail;
   253â†’		}
   254â†’	} else {
   255â†’		rejfp = NULL;
   256â†’	}
   257â†’
   258â†’	if ( infile != NULL ) {
   259â†’		if (( ldiffp = ldif_open( infile, "r" )) == NULL ) {
   260â†’			perror( infile );
   261â†’			retval = EXIT_FAILURE;
   262â†’			goto fail;
   263â†’		}
   264â†’	} else {
   265â†’		ldifdummy.fp = stdin;
   266â†’		ldiffp = &ldifdummy;
   267â†’	}
   268â†’
   269â†’	if ( debug ) ldif_debug = debug;
   270â†’
   271â†’	ld = tool_conn_setup( dont, 0 );
   272â†’
   273â†’	if ( !dont ) {
   274â†’		tool_bind( ld );
   275â†’	}
   276â†’
   277â†’	if( txn ) {
   278â†’		/* start transaction */
   279â†’		rc = ldap_txn_start_s( ld, NULL, NULL, &txn_id );
   280â†’		if( rc != LDAP_SUCCESS || !txn_id ) {
   281â†’			tool_perror( "ldap_txn_start_s", rc, NULL, NULL, NULL, NULL );
   282â†’			if( txn > 1 ) {
   283â†’				retval = EXIT_FAILURE;
   284â†’				goto fail;
   285â†’			}
   286â†’			txn = 0;
   287â†’		}
   288â†’	}
   289â†’
   290â†’	if( txn ) {
   291â†’		c[i].ldctl_oid = LDAP_CONTROL_TXN_SPEC;
   292â†’		c[i].ldctl_value = *txn_id;
   293â†’		c[i].ldctl_iscritical = 1;
   294â†’		i++;
   295â†’	}
   296â†’
   297â†’	tool_server_controls( ld, c, i );
   298â†’
   299â†’	rc = 0;
   300â†’	retval = 0;
   301â†’	lineno = 1;
   302â†’	while (( rc == 0 || contoper ) && ( ldifrc = ldif_read_record( ldiffp, &nextline,
   303â†’		&rbuf, &lmax )) > 0 )
   304â†’	{
   305â†’		if ( rejfp ) {
   306â†’			len = strlen( rbuf );
   307â†’			if (( rejbuf = (char *)ber_memalloc( len+1 )) == NULL ) {
   308â†’				perror( "malloc" );
   309â†’				retval = EXIT_FAILURE;
   310â†’				goto fail;
   311â†’			}
   312â†’			memcpy( rejbuf, rbuf, len+1 );
   313â†’		}
   314â†’
   315â†’		if ( interval ) {
   316â†’			select( 0, NULL, NULL, NULL, &interval_tv );
   317â†’		}
   318â†’
   319â†’		rc = process_ldif_rec( rbuf, lineno );
   320â†’		lineno = nextline+1;
   321â†’
   322â†’		if ( rc ) retval = rc;
   323â†’		if ( rc && rejfp ) {
   324â†’			fprintf(rejfp, _("# Error: %s (%d)"), ldap_err2string(rc), rc);
   325â†’
   326â†’			matched_msg = NULL;
   327â†’			ldap_get_option(ld, LDAP_OPT_MATCHED_DN, &matched_msg);
   328â†’			if ( matched_msg != NULL ) {
   329â†’				if ( *matched_msg != '\0' ) {
   330â†’					fprintf( rejfp, _(", matched DN: %s"), matched_msg );
   331â†’				}
   332â†’				ldap_memfree( matched_msg );
   333â†’			}
   334â†’
   335â†’			error_msg = NULL;
   336â†’			ldap_get_option(ld, LDAP_OPT_DIAGNOSTIC_MESSAGE, &error_msg);
   337â†’			if ( error_msg != NULL ) {
   338â†’				if ( *error_msg != '\0' ) {
   339â†’					fprintf( rejfp, _(", additional info: %s"), error_msg );
   340â†’				}
   341â†’				ldap_memfree( error_msg );
   342â†’			}
   343â†’			fprintf( rejfp, "\n%s\n", rejbuf );
   344â†’		}
   345â†’
   346â†’		if (rejfp) ber_memfree( rejbuf );
   347â†’	}
   348â†’	ber_memfree( rbuf );
   349â†’
   350â†’	if ( ldifrc < 0 )
   351â†’		retval = LDAP_OTHER;
   352â†’
   353â†’	if( retval == 0 && txn ) {
   354â†’		rc = ldap_set_option( ld, LDAP_OPT_SERVER_CONTROLS, NULL );
   355â†’		if ( rc != LDAP_OPT_SUCCESS ) {
   356â†’			fprintf( stderr, "Could not unset controls for ldap_txn_end\n");
   357â†’		}
   358â†’
   359â†’		/* create transaction */
   360â†’		rc = ldap_txn_end_s( ld, !txnabort, txn_id, NULL, NULL, NULL );
   361â†’		if( rc != LDAP_SUCCESS ) {
   362â†’			tool_perror( "ldap_txn_end_s", rc, NULL, NULL, NULL, NULL );
