   380â†’static int
   381â†’process_ldif_rec( char *rbuf, unsigned long linenum )
   382â†’{
   383â†’	LDIFRecord lr;
   384â†’	int lrflags = ldapadd ? LDIF_DEFAULT_ADD : 0;
   385â†’	int rc;
   386â†’	struct berval rbuf_bv;
   387â†’
   388â†’#ifdef TEST_LDIF_API
   389â†’	if ( getenv( "LDIF_ENTRIES_ONLY" ) ) {
   390â†’		lrflags |= LDIF_ENTRIES_ONLY;
   391â†’	}
   392â†’	if ( getenv( "LDIF_NO_CONTROLS" ) ) {
   393â†’		lrflags |= LDIF_NO_CONTROLS;
   394â†’	}
   395â†’#endif /* TEST_LDIF_API */
   396â†’
   397â†’	rbuf_bv.bv_val = rbuf;
   398â†’	rbuf_bv.bv_len = 0; /* not used */
   399â†’	rc = ldap_parse_ldif_record( &rbuf_bv, linenum, &lr, prog, lrflags );
   400â†’
   401â†’	/* If default controls are set (as with -M option) and controls are
   402â†’	   specified in the LDIF file, we must add the default controls to
   403â†’	   the list of controls sent with the ldap operation.
   404â†’	*/
   405â†’	if ( rc == 0 ) {
   406â†’		if (lr.lr_ctrls) {
   407â†’			LDAPControl **defctrls = NULL;   /* Default server controls */
   408â†’			LDAPControl **newctrls = NULL;
   409â†’			ldap_get_option(ld, LDAP_OPT_SERVER_CONTROLS, &defctrls);
   410â†’			if (defctrls) {
   411â†’				int npc=0;                       /* Num of LDIF controls */
   412â†’				int ndefc=0;                     /* Num of default controls */
   413â†’				while (lr.lr_ctrls[npc]) npc++;       /* Count LDIF controls */
   414â†’				while (defctrls[ndefc]) ndefc++; /* Count default controls */
   415â†’				newctrls = ber_memrealloc(lr.lr_ctrls,
   416â†’					(npc+ndefc+1)*sizeof(LDAPControl*));
   417â†’
   418â†’				if (newctrls == NULL) {
   419â†’					rc = LDAP_NO_MEMORY;
